<?php
session_start();

// Database configuration
$dbHost = 'localhost';
$dbName = 'your_database';
$dbUser = 'your_db_user';
$dbPass = 'your_db_password';

try {
    $pdo = new PDO("mysql:host=$dbHost;dbname=$dbName;charset=utf8mb4", $dbUser, $dbPass, [
        PDO::ATTR_ERRMODE => PDO::ERRMODE_EXCEPTION,
        PDO::ATTR_DEFAULT_FETCH_MODE => PDO::FETCH_ASSOC,
        PDO::ATTR_EMULATE_PREPARES => false,
    ]);
} catch (PDOException $e) {
    die('Database connection failed.');
}

// --- Authentication check (replace with your actual auth logic) ---
if (empty($_SESSION['admin_logged_in']) || $_SESSION['admin_logged_in'] !== true) {
    http_response_code(403);
    die('Access denied. Admin authentication required.');
}

// --- CSRF token generation ---
if (empty($_SESSION['csrf_token'])) {
    $_SESSION['csrf_token'] = bin2hex(random_bytes(32));
}

$message = '';
$messageType = '';

// --- Process deletion ---
if ($_SERVER['REQUEST_METHOD'] === 'POST' && isset($_POST['user_id'])) {
    // CSRF validation
    if (empty($_POST['csrf_token']) || !hash_equals($_SESSION['csrf_token'], $_POST['csrf_token'])) {
        http_response_code(403);
        die('Invalid CSRF token. Request rejected.');
    }

    $userId = filter_input(INPUT_POST, 'user_id', FILTER_VALIDATE_INT);

    if ($userId === false || $userId === null || $userId <= 0) {
        $message = 'Invalid user ID provided.';
        $messageType = 'error';
    } else {
        // Prevent admin from deleting themselves
        if (isset($_SESSION['admin_user_id']) && (int)$_SESSION['admin_user_id'] === $userId) {
            $message = 'You cannot delete your own admin account.';
            $messageType = 'error';
        } else {
            // Check if user exists
            $stmt = $pdo->prepare('SELECT id, username, email FROM users WHERE id = :id');
            $stmt->execute([':id' => $userId]);
            $user = $stmt->fetch();

            if (!$user) {
                $message = 'User not found.';
                $messageType = 'error';
            } else {
                // Delete the user
                $deleteStmt = $pdo->prepare('DELETE FROM users WHERE id = :id');
                $deleteStmt->execute([':id' => $userId]);

                if ($deleteStmt->rowCount() > 0) {
                    $message = "User \"{$user['username']}\" (ID: {$userId}) has been deleted successfully.";
                    $messageType = 'success';

                    // Regenerate CSRF token after successful action
                    $_SESSION['csrf_token'] = bin2hex(random_bytes(32));
                } else {
                    $message = 'Failed to delete user. Please try again.';
                    $messageType = 'error';
                }
            }
        }
    }
}

// --- Fetch all users for display ---
$users = $pdo->query('SELECT id, username, email, created_at FROM users ORDER BY id ASC')->fetchAll();
